// vscode-extension/webview/src/details/DetailsApp.tsx

import React, { useState, useEffect, useRef } from 'react';
import { Spin, Alert, Button } from 'antd';
import { ReloadOutlined, LoadingOutlined } from '@ant-design/icons';
import DetailHeader from './DetailHeader';
import DetailContent from './DetailContent';
import { useL10n } from '../l10n';

// д»Һ window иҺ·еҸ– vscode APIпјҲз”ұ details/main.tsx жіЁе…Ҙпјү
declare const vscode: {
  postMessage: (message: any) => void;
};

// жң¬ең°зұ»еһӢе®ҡд№ү
export interface MarketplaceSource {
  source: 'github' | 'url' | 'directory' | 'git';
  repo?: string;
  url?: string;
}

export interface PluginDetailData {
  name: string;
  description: string;
  version: string;
  author?: string;
  homepage?: string;
  category?: string;
  marketplace: string;
  installed: boolean;
  enabled?: boolean;
  scope?: 'user' | 'project' | 'local';
  updateAvailable?: boolean;
  readme?: string;
  skills?: SkillInfo[];
  agents?: AgentInfo[];
  hooks?: HookInfo[];
  mcps?: McpInfo[];
  commands?: CommandInfo[];
  lsps?: LspInfo[];
  outputStyles?: OutputStyleInfo[];
  repository?: RepositoryInfo;
  dependencies?: string[];
  license?: string;
  isRemoteSource?: boolean;
  localPath?: string;
  marketplaceSource?: MarketplaceSource;
}

export interface SkillInfo {
  name: string;
  description?: string;
  filePath?: string;
}

export interface AgentInfo {
  name: string;
  description?: string;
  filePath?: string;
}

export interface HookInfo {
  event: string;
  filePath?: string;
  hooks: HookConfig[];
}

export interface HookConfig {
  type: string;
  matcher?: string;
  command?: string;
  skill?: string;
}

export interface McpInfo {
  name: string;
  filePath?: string;
}

export interface LspInfo {
  language: string;
  filePath?: string;
}

export interface CommandInfo {
  name: string;
  description?: string;
  filePath?: string;
}

export interface OutputStyleInfo {
  name: string;
  filePath?: string;
}

export interface RepositoryInfo {
  type: 'github' | 'gitlab' | 'other';
  url: string;
  stars?: number;
}

const DetailsApp: React.FC = () => {
  const { t } = useL10n();
  const [plugin, setPlugin] = useState<PluginDetailData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [readyNotified, setReadyNotified] = useState(false);
  const messageReceivedRef = useRef(false); // дҪҝз”Ё ref йҒҝе…Қй—ӯеҢ…й—®йўҳ

  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      const message = event.data;
      switch (message.type) {
        case 'pluginDetail':
          setPlugin(message.payload.plugin);
          setLoading(false);
          setError(null);
          messageReceivedRef.current = true; // ж Үи®°е·Іж”¶еҲ°ж¶ҲжҒҜ
          break;
        case 'detailUpdate':
        case 'statusUpdate':
          // жҸ’д»¶ж•°жҚ®еҸҳжӣҙж—¶пјҢиҜ·жұӮе®Ңж•ҙйҮҚж–°жӢүеҸ–
          vscode.postMessage({
            type: 'refreshPluginDetail'
          });
          break;
        case 'error':
          setError(message.payload.message);
          setLoading(false);
          messageReceivedRef.current = true;
          break;
      }
    };

    window.addEventListener('message', handleMessage);

    // йҖҡзҹҘжү©еұ•дҫ§ webview е·ІеҮҶеӨҮеҘҪжҺҘж”¶ж•°жҚ®
    if (!readyNotified) {
      vscode.postMessage({ type: 'ready' });
      setReadyNotified(true);
    }

    // ж·»еҠ и¶…ж—¶еӨ„зҗҶпјҡеҰӮжһң 30 з§’еҗҺиҝҳжІЎж”¶еҲ°ж¶ҲжҒҜпјҢеҸӘеҒңжӯўеҠ иҪҪзҠ¶жҖҒ
    // дёҚдјҡиҰҶзӣ–е·ІеҠ иҪҪзҡ„жҸ’д»¶еҶ…е®№
    const timeoutId = setTimeout(() => {
      if (!messageReceivedRef.current) { // дҪҝз”Ё ref жЈҖжҹҘжңҖж–°зҡ„зҠ¶жҖҒ
        console.error('[DetailsApp] Timeout waiting for plugin data');
        setLoading(false); // еҒңжӯўеҠ иҪҪзҠ¶жҖҒпјҢдҪҶдёҚи®ҫзҪ® error
        // дёҚи®ҫзҪ® setErrorпјҢйҒҝе…ҚиҰҶзӣ–е·ІжҳҫзӨәзҡ„жҸ’д»¶еҶ…е®№
      }
    }, 30000);

    return () => {
      window.removeEventListener('message', handleMessage);
      clearTimeout(timeoutId);
    };
  }, [readyNotified]); // еҸӘдҫқиө– readyNotifiedпјҢзЎ®дҝқ effect еҸӘжү§иЎҢдёҖж¬Ў

  const handleInstall = (scope: 'user' | 'project') => {
    if (!plugin) return;
    vscode.postMessage({
      type: 'installPlugin',
      payload: {
        pluginName: plugin.name,
        marketplace: plugin.marketplace,
        scope
      }
    });
  };

  const handleUninstall = () => {
    if (!plugin) return;
    vscode.postMessage({
      type: 'uninstallPlugin',
      payload: { pluginName: plugin.name }
    });
  };

  const handleEnable = () => {
    if (!plugin) return;
    vscode.postMessage({
      type: 'enablePlugin',
      payload: { pluginName: plugin.name, marketplace: plugin.marketplace }
    });
  };

  const handleDisable = () => {
    if (!plugin) return;
    vscode.postMessage({
      type: 'disablePlugin',
      payload: { pluginName: plugin.name, marketplace: plugin.marketplace }
    });
  };

  const handleOpenExternal = (url: string) => {
    vscode.postMessage({
      type: 'openExternal',
      payload: { url }
    });
  };

  const handleOpenFile = (filePath: string) => {
    vscode.postMessage({
      type: 'openFile',
      payload: { filePath }
    });
  };

  const handleOpenDirectory = (directoryPath: string) => {
    vscode.postMessage({
      type: 'openDirectory',
      payload: { directoryPath }
    });
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <Spin indicator={<LoadingOutlined style={{ fontSize: 32 }} spin />} tip={t('detail.loading')} />
      </div>
    );
  }

  // еҸӘжңүеңЁжІЎжңүд»»дҪ•жҸ’д»¶ж•°жҚ®ж—¶жүҚжҳҫзӨәй”ҷиҜҜйЎөйқў
  if (!plugin && error) {
    return (
      <div style={{ padding: 24 }}>
        <Alert
          type="error"
          description={error}
          action={
            <Button size="small" danger onClick={() => window.location.reload()}>
              <ReloadOutlined /> {t('detail.retry')}
            </Button>
          }
          showIcon
        />
      </div>
    );
  }

  // жІЎжңүжҸ’д»¶ж•°жҚ®дё”жІЎжңүй”ҷиҜҜ
  if (!plugin) {
    return (
      <div style={{ padding: 24 }}>
        <Alert description={t('detail.notFound')} type="warning" showIcon />
      </div>
    );
  }

  return (
    <div style={{ padding: 20, maxWidth: 1200, minWidth: 800, margin: '0 auto' }}>
      {/* еҰӮжһңжңүжҸ’д»¶ж•°жҚ®дҪҶжңүй”ҷиҜҜпјҢеңЁйЎ¶йғЁжҳҫзӨәиӯҰе‘ҠпјҲдёҚиҰҶзӣ–еҶ…е®№пјү */}
      {error && (
        <Alert
          type="warning"
          description={error}
          closable
          style={{ marginBottom: 16 }}
          showIcon
        />
      )}
      <DetailHeader
        plugin={plugin}
        onInstall={handleInstall}
        onUninstall={handleUninstall}
        onEnable={handleEnable}
        onDisable={handleDisable}
        onOpenExternal={handleOpenExternal}
        onOpenDirectory={handleOpenDirectory}
      />
      <DetailContent plugin={plugin} onOpenFile={handleOpenFile} />
    </div>
  );
};

export default DetailsApp;
